import React, { useState, useEffect } from "react";

import axios from "axios";
import { Container, Card, CardBody, Spinner } from "reactstrap";


const Location = () => {

    const [ip, setip] = useState(null);
    const [geodata, setgeodata] = useState(null);

    const API_KEY = "at_fKxM6jvVF8reBa0K8FhxMqiE5JDxH";

    const fetchIpAddress  =async ()=>{
        try {

            const response = await axios.get("https://api.ipify.org?format=json");
            setip(response.data.ip);
            
        } catch (error) {
            console.error("Error fetching IP address:", error.message);
        }
    };


    const getGeoLocationData  =async ()=>{

        if(!ip) return;
        try {
            const response = await axios.get(`https://geo.ipify.org/api/v2/country+city?apiKey=${API_KEY}&ipAddress=${ip}`);
            setgeodata(response.data);
            console.log("GeoLocation Data:", response.data);
            console.log("Internal Logic - Lat:", response.data.location.lat);
      console.log("Internal Logic - Lon:", response.data.location.lng);
        } catch (error) {
             console.error("Error fetching IP address:", error.message);
        }
    };

      useEffect(() => {
    fetchIpAddress();
  }, []);

  useEffect(() => {
    if (ip) {
      getGeoLocationData();
    }
  }, [ip]);





    return (
        <Container className="d-flex justify-content-center mt-5">
      {/* استخدمنا كلاسات بسيطة: shadow-sm للظل، و rounded-4 للزوايا المنحنية */}
      <Card className="border-0 shadow-sm rounded-4" style={{ maxWidth: "400px", width: "100%" }}>
        <CardBody className="p-4">
          <h5 className="text-secondary fw-bold mb-4">Location Info</h5>

          {/* قسم الـ IP بتنسيق مبسط */}
          <div className="mb-3">
            <small className="text-muted d-block">IP Address</small>
            <span className="fw-medium">{ip || <Spinner size="sm" color="primary" />}</span>
          </div>

          {/* قسم الموقع بخلفية خفيفة جداً */}
          {geodata ? (
            <div className="p-3 bg-light rounded-3">
              <div className="mb-2">
                <small className="text-muted d-block">Country</small>
                <span className="fw-bold">{geodata.location.country}</span>
              </div>
              <div>
                <small className="text-muted d-block">Region</small>
                <span className="fw-bold">{geodata.location.region}</span>
              </div>
            </div>
          ) : (
            <div className="text-center p-3">
              <Spinner size="sm" color="secondary" />
            </div>
          )}
        </CardBody>
      </Card>
    </Container>
     );
}
 
export default Location;
